import{_ as n,p as s,q as a,a1 as e}from"./framework-5866ffd3.js";const t={},o=e(`<h1 id="c-输出-打印文本" tabindex="-1"><a class="header-anchor" href="#c-输出-打印文本" aria-hidden="true">#</a> C 输出（打印文本）</h1><p><code>printf()</code> 函数用于输出值/打印文本</p><h2 id="格式控制符" tabindex="-1"><a class="header-anchor" href="#格式控制符" aria-hidden="true">#</a> 格式控制符</h2><table><thead><tr><th>格式控制符</th><th>说明</th></tr></thead><tbody><tr><td><code>%c</code></td><td>输出一个单一的字符</td></tr><tr><td><code>%hd</code> <code>%d</code> <code>%ld</code></td><td>以十进制、有符号的形式输出 short、int、long 类型的整数</td></tr><tr><td><code>%hu</code> <code>%u</code> <code>%lu</code></td><td>以十进制、无符号的形式输出 short、int、long 类型的整数</td></tr><tr><td><code>%ho</code> <code>%o</code> <code>%lo</code></td><td>以八进制、不带前缀、无符号的形式输出 short、int、long 类型的整数</td></tr><tr><td><code>%#ho</code> <code>%#o</code> <code>%#lo</code></td><td>以八进制、带前缀、无符号的形式输出 short、int、long 类型的整数</td></tr><tr><td><code>%hx</code> <code>%x</code> <code>%lx</code><br> <code>%hX</code> <code>%X</code> <code>%lX</code></td><td>以十六进制、不带前缀、无符号的形式输出 short、int、long 类型的整数。如果 x 小写，那么输出的十六进制数字也小写；如果 X 大写，那么输出的十六进制数字也大写。</td></tr><tr><td><code>%#hx</code> <code>%#x</code> <code>%#lx</code><br><code>%#hX</code> <code>%#X</code> <code>%#lX</code></td><td>以十六进制、带前缀、无符号的形式输出 short、int、long 类型的整数。如果 x 小写，那么输出的十六进制数字和前缀都小写；如果 X 大写，那么输出的十六进制数字和前缀都大写。</td></tr><tr><td><code>%f</code> <code>%lf</code></td><td>以十进制的形式输出 float<code></code>、double 类型的小数</td></tr><tr><td><code>%e</code> <code>%le</code> <code>%E</code> <code>%lE</code></td><td>以指数的形式输出 float、double 类型的小数。如果 e 小写，那么输出结果中的 e 也小写；如果 E 大写，那么输出结果中的 E 也大写。</td></tr><tr><td><code>%g</code> <code>%lg</code> <code>%G</code> <code>%lG</code></td><td>以十进制和指数中较短的形式输出 float、double 类型的小数，并且小数部分的最后不会添加多余的 0。如果 g 小写，那么当以指数形式输出时 e 也小写；如果 G 大写，那么当以指数形式输出时 E 也大写。</td></tr><tr><td><code>%s</code></td><td>输出一个字符串</td></tr></tbody></table><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;stdio.h&gt;</span></span>

<span class="token keyword">int</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;Hello World!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>您可以根据需要添加任意数量的 <code>printf()</code> 函数。 但是，请注意，它不会在输出末尾插入新行：</p><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;stdio.h&gt;</span></span>

<span class="token keyword">int</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;Hello World!&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;I am learning C.&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="d-输出整数" tabindex="-1"><a class="header-anchor" href="#d-输出整数" aria-hidden="true">#</a> <code>%d</code> 输出整数</h3><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;stdio.h&gt;</span></span>

<span class="token keyword">int</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
  <span class="token keyword">int</span> testInteger <span class="token operator">=</span> <span class="token number">5</span><span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;Number = %d&quot;</span><span class="token punctuation">,</span> testInteger<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>输出 <code>Number = 5</code></p><h3 id="f-输出浮点型数据" tabindex="-1"><a class="header-anchor" href="#f-输出浮点型数据" aria-hidden="true">#</a> <code>%f</code> 输出浮点型数据</h3><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;stdio.h&gt;</span></span>
<span class="token keyword">int</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
  <span class="token keyword">float</span> f<span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;Enter a number: &quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token comment">// %f 匹配浮点型数据</span>
  <span class="token function">scanf</span><span class="token punctuation">(</span><span class="token string">&quot;%f&quot;</span><span class="token punctuation">,</span> <span class="token operator">&amp;</span>f<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;Value = %f&quot;</span><span class="token punctuation">,</span> f<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="short-int-long" tabindex="-1"><a class="header-anchor" href="#short-int-long" aria-hidden="true">#</a> short/int/long</h2><table><thead><tr><th></th><th>short</th><th>int</th><th>long</th></tr></thead><tbody><tr><td>8 进制</td><td><code>%ho</code></td><td><code>%o</code></td><td><code>%lo</code></td></tr><tr><td>10 进制</td><td><code>%hd</code></td><td><code>%d</code></td><td><code>%ld</code></td></tr><tr><td>16 进制</td><td><code>%hx</code> 或者 <code>%hX</code></td><td><code>%x</code> 或者 <code>%X</code></td><td><code>%lx</code> 或者 <code>%lX</code></td></tr></tbody></table><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token keyword">short</span> a <span class="token operator">=</span> <span class="token number">0</span>b1010110<span class="token punctuation">;</span>  <span class="token comment">// 2 进制数字</span>
<span class="token keyword">int</span> b <span class="token operator">=</span> <span class="token number">02713</span><span class="token punctuation">;</span>        <span class="token comment">// 8 进制数字</span>
<span class="token keyword">long</span> c <span class="token operator">=</span> <span class="token number">0X1DAB83</span><span class="token punctuation">;</span>    <span class="token comment">// 16 进制数字</span>

<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;a=%ho, b=%o, c=%lo\\n&quot;</span><span class="token punctuation">,</span> a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 以 8 进制形似输出</span>
<span class="token comment">// a=126, b=2713, c=7325603</span>
<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;a=%hd, b=%d, c=%ld\\n&quot;</span><span class="token punctuation">,</span> a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 以 10 进制形式输出</span>
<span class="token comment">// a=86, b=1483, c=1944451</span>
<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;a=%hx, b=%x, c=%lx\\n&quot;</span><span class="token punctuation">,</span> a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 以 16 进制形式输出（字母小写）</span>
<span class="token comment">// a=56, b=5cb, c=1dab83</span>
<span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;a=%hX, b=%X, c=%lX\\n&quot;</span><span class="token punctuation">,</span> a<span class="token punctuation">,</span> b<span class="token punctuation">,</span> c<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 以 16 进制形式输出（字母大写）</span>
<span class="token comment">// a=56, b=5CB, c=1DAB83</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="控制空格数" tabindex="-1"><a class="header-anchor" href="#控制空格数" aria-hidden="true">#</a> 控制空格数</h2><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;stdio.h&gt;</span></span>
<span class="token keyword">int</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
<span class="token punctuation">{</span>
  <span class="token keyword">int</span> a1<span class="token operator">=</span><span class="token number">20</span><span class="token punctuation">,</span> a2<span class="token operator">=</span><span class="token number">345</span><span class="token punctuation">,</span> a3<span class="token operator">=</span><span class="token number">700</span><span class="token punctuation">,</span> a4<span class="token operator">=</span><span class="token number">22</span><span class="token punctuation">;</span>
  <span class="token keyword">int</span> b1<span class="token operator">=</span><span class="token number">56720</span><span class="token punctuation">,</span> b2<span class="token operator">=</span><span class="token number">9999</span><span class="token punctuation">,</span> b3<span class="token operator">=</span><span class="token number">20098</span><span class="token punctuation">,</span> b4<span class="token operator">=</span><span class="token number">2</span><span class="token punctuation">;</span>
  <span class="token keyword">int</span> c1<span class="token operator">=</span><span class="token number">233</span><span class="token punctuation">,</span> c2<span class="token operator">=</span><span class="token number">205</span><span class="token punctuation">,</span> c3<span class="token operator">=</span><span class="token number">1</span><span class="token punctuation">,</span> c4<span class="token operator">=</span><span class="token number">6666</span><span class="token punctuation">;</span>
  <span class="token keyword">int</span> d1<span class="token operator">=</span><span class="token number">34</span><span class="token punctuation">,</span> d2<span class="token operator">=</span><span class="token number">0</span><span class="token punctuation">,</span> d3<span class="token operator">=</span><span class="token number">23</span><span class="token punctuation">,</span> d4<span class="token operator">=</span><span class="token number">23006783</span><span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%-9d %-9d %-9d %-9d\\n&quot;</span><span class="token punctuation">,</span> a1<span class="token punctuation">,</span> a2<span class="token punctuation">,</span> a3<span class="token punctuation">,</span> a4<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%-9d %-9d %-9d %-9d\\n&quot;</span><span class="token punctuation">,</span> b1<span class="token punctuation">,</span> b2<span class="token punctuation">,</span> b3<span class="token punctuation">,</span> b4<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%-9d %-9d %-9d %-9d\\n&quot;</span><span class="token punctuation">,</span> c1<span class="token punctuation">,</span> c2<span class="token punctuation">,</span> c3<span class="token punctuation">,</span> c4<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%-9d %-9d %-9d %-9d\\n&quot;</span><span class="token punctuation">,</span> d1<span class="token punctuation">,</span> d2<span class="token punctuation">,</span> d3<span class="token punctuation">,</span> d4<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>输出结果：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token number">20</span>        <span class="token number">345</span>       <span class="token number">700</span>       <span class="token number">22</span>
<span class="token number">56720</span>     <span class="token number">9999</span>      <span class="token number">20098</span>     <span class="token number">2</span>
<span class="token number">233</span>       <span class="token number">205</span>       <span class="token number">1</span>         <span class="token number">6666</span>
<span class="token number">34</span>        <span class="token number">0</span>         <span class="token number">23</span>        <span class="token number">23006783</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>%-9d</code> 中，<code>d</code> 表示以 10 进制输出，<code>9</code> 表示最少占 <code>9</code> 个字符的宽度，宽度不足以空格补齐，<code>-</code> 表示左对齐。综合起来，<code>%-9d</code> 表示以 10 进制输出，左对齐，宽度最小为 <code>9</code> 个字符。大家可以亲自试试 <code>%9d</code> 的输出效果。</p><h2 id="标志字符" tabindex="-1"><a class="header-anchor" href="#标志字符" aria-hidden="true">#</a> 标志字符</h2><ul><li><code>-</code> 表示左对齐。如果没有，就按照默认的对齐方式，默认一般为右对齐。</li><li><code>+</code> 用于整数或者小数，表示输出符号（正负号）。如果没有，那么只有负数才会输出符号。</li><li><code>空格</code> 用于整数或者小数，输出值为正时冠以空格，为负时冠以负号。</li><li><code>#</code> 对于八进制（<code>%o</code>）和十六进制（<code>%x</code> / <code>%X</code>）整数，<code>#</code> 表示在输出时添加前缀；八进制的前缀是 <code>0</code>，十六进制的前缀是 <code>0x</code> / <code>0X</code>。对于小数（<code>%f</code> / <code>%e</code> / <code>%g</code>），<code>#</code> 表示强迫输出小数点。如果没有小数部分，默认是不输出小数点的，加上 <code>#</code> 以后，即使没有小数部分也会带上小数点。</li></ul><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;stdio.h&gt;</span></span>
<span class="token keyword">int</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  <span class="token keyword">int</span> m <span class="token operator">=</span> <span class="token number">192</span><span class="token punctuation">,</span> n <span class="token operator">=</span> <span class="token operator">-</span><span class="token number">943</span><span class="token punctuation">;</span>
  <span class="token keyword">float</span> f <span class="token operator">=</span> <span class="token number">84.342</span><span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;m=%10d, m=%-10d\\n&quot;</span><span class="token punctuation">,</span> m<span class="token punctuation">,</span> m<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 演示 - 的用法</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;m=%+d, n=%+d\\n&quot;</span><span class="token punctuation">,</span> m<span class="token punctuation">,</span> n<span class="token punctuation">)</span><span class="token punctuation">;</span>     <span class="token comment">// 演示 + 的用法</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;m=% d, n=% d\\n&quot;</span><span class="token punctuation">,</span> m<span class="token punctuation">,</span> n<span class="token punctuation">)</span><span class="token punctuation">;</span>     <span class="token comment">// 演示空格的用法</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;f=%.0f, f=%#.0f\\n&quot;</span><span class="token punctuation">,</span> f<span class="token punctuation">,</span> f<span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 演示 # 的用法</span>
  <span class="token keyword">return</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>运行结果：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">m</span><span class="token operator">=</span>       <span class="token number">192</span>, <span class="token assign-left variable">m</span><span class="token operator">=</span><span class="token number">192</span> <span class="token comment"># 当以%10d输出 m 时，是右对齐，</span>
                    <span class="token comment"># 所以在 192 前面补七个空格；</span>
                    <span class="token comment"># 当以%-10d输出 m 时，是左对齐，所以在 192 后面补七个空格。</span>

<span class="token assign-left variable">m</span><span class="token operator">=</span>+192, <span class="token assign-left variable">n</span><span class="token operator">=</span>-943      <span class="token comment"># m 是正数，以 %+d 输出时要带上正号；n 是负数，以%+d输出时要带上负号。</span>

<span class="token assign-left variable">m</span><span class="token operator">=</span> <span class="token number">192</span>, <span class="token assign-left variable">n</span><span class="token operator">=</span>-943      <span class="token comment"># m 是正数，以 % d 输出时要在前面加空格；n 是负数，以% d输出时要在前面加负号。</span>

<span class="token assign-left variable">f</span><span class="token operator">=</span><span class="token number">84</span>, <span class="token assign-left variable">f</span><span class="token operator">=</span><span class="token number">84</span>.         <span class="token comment"># %.0f表示保留 0 位小数，也就是只输出整数部分，不输出小数部分。</span>
                    <span class="token comment"># 默认情况下，这种输出形式是不带小数点的，但是如果有了#标志，</span>
                    <span class="token comment"># 那么就要在整数的后面“硬加上”一个小数点，以和纯整数区分开。</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="格式控制符-1" tabindex="-1"><a class="header-anchor" href="#格式控制符-1" aria-hidden="true">#</a> 格式控制符</h2><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>%[flag][width][.precision]type
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>[ ]</code> 表示此处的内容可有可无，是可以省略的。</li><li><code>type</code> (必须有)表示输出类型，比如 <code>%d</code>、<code>%f</code>、<code>%c</code>、<code>%lf</code>，<code>type</code> 就分别对应 <code>d</code>、<code>f</code>、<code>c</code>、<code>lf</code>；再如，<code>%-9d</code> 中 <code>type</code> 对应 <code>d</code>。</li><li><code>width</code> 表示最小输出宽度，也就是至少占用几个字符的位置；例如，<code>%-9d</code> 中 <code>width</code> 对应 <code>9</code>，表示输出结果最少占用 <code>9</code> 个字符的宽度。</li></ul><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;stdio.h&gt;</span></span>
<span class="token keyword">int</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  <span class="token keyword">int</span> n <span class="token operator">=</span> <span class="token number">234</span><span class="token punctuation">;</span>
  <span class="token keyword">float</span> f <span class="token operator">=</span> <span class="token number">9.8</span><span class="token punctuation">;</span>
  <span class="token keyword">char</span> c <span class="token operator">=</span> <span class="token char">&#39;@&#39;</span><span class="token punctuation">;</span>
  <span class="token keyword">char</span> <span class="token operator">*</span>str <span class="token operator">=</span> <span class="token string">&quot;https://github.com/jaywcjlove/c-tutorial&quot;</span><span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;%10d%12f%4c%8s&quot;</span><span class="token punctuation">,</span> n<span class="token punctuation">,</span> f<span class="token punctuation">,</span> c<span class="token punctuation">,</span> str<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>运行结果：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>       234    9.800000   @https://github.com/jaywcjlove/c-tutorial
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>对输出结果的说明：</p><ul><li><code>n</code> 的指定输出宽度为 10，234 的宽度为 3，所以前边要补上 7 个空格。</li><li><code>f</code> 的指定输出宽度为 12，9.800000 的宽度为 8，所以前边要补上 4 个空格。</li><li><code>str</code> 的指定输出宽度为 8，&quot;https://github.com/jaywcjlove/c-tutorial&quot; 的宽度为 <code>40</code>，超过了 8，所以指定输出宽度不再起作用，而是按照 <code>str</code> 的实际宽度输出。</li></ul><h2 id="输出精度-宽度" tabindex="-1"><a class="header-anchor" href="#输出精度-宽度" aria-hidden="true">#</a> 输出精度/宽度</h2><div class="language-c line-numbers-mode" data-ext="c"><pre class="language-c"><code><span class="token macro property"><span class="token directive-hash">#</span><span class="token directive keyword">include</span> <span class="token string">&lt;stdio.h&gt;</span></span>
<span class="token keyword">int</span> <span class="token function">main</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>
  <span class="token keyword">int</span> n <span class="token operator">=</span> <span class="token number">123456</span><span class="token punctuation">;</span>
  <span class="token keyword">double</span> f <span class="token operator">=</span> <span class="token number">882.923672</span><span class="token punctuation">;</span>
  <span class="token keyword">char</span> <span class="token operator">*</span>str <span class="token operator">=</span> <span class="token string">&quot;abcdefghi&quot;</span><span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;n: %.9d  %.4d\\n&quot;</span><span class="token punctuation">,</span> n<span class="token punctuation">,</span> n<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;f: %.2lf  %.4lf  %.10lf\\n&quot;</span><span class="token punctuation">,</span> f<span class="token punctuation">,</span> f<span class="token punctuation">,</span> f<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token function">printf</span><span class="token punctuation">(</span><span class="token string">&quot;str: %.5s  %.15s\\n&quot;</span><span class="token punctuation">,</span> str<span class="token punctuation">,</span> str<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> <span class="token number">0</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>运行结果：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>n: 000123456  123456
f: 882.92  882.9237  882.9236720000
str: abcde  abcdefghi
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>对输出结果的说明：</p><ul><li>对于 <code>n</code>，<code>.precision</code> 表示最小输出宽度。n 本身的宽度为 6，当 <code>precision</code> 为 9 时，大于 6，要在 n 的前面补 3 个 0；当 <code>precision</code> 为 4 时，小于 6，不再起作用。</li><li>对于 <code>f</code>，<code>.precision</code> 表示输出精度。f 的小数部分有 6 位数字，当 <code>precision</code> 为 2 或者 4 时，都小于 6，要按照四舍五入的原则截断小数；当 precision 为 10 时，大于 6，要在小数的后面补四个 0。</li><li>对于 <code>str</code>，<code>.precision</code> 表示最大输出宽度。<code>str</code> 本身的宽度为 9，当 <code>precision</code> 为 5 时，小于 9，要截取 str 的前 5 个字符；当 precision 为 15 时，大于 9，不再起作用。</li></ul>`,39),c=[o];function p(i,l){return s(),a("div",null,c)}const u=n(t,[["render",p],["__file","c_output.html.vue"]]);export{u as default};
